/**
 * Bench: Phyle comic parallax — full artistic pipeline demo.
 *
 * Simulates a comic panel with:
 * - Foreground character (constant depth, small region)
 * - Midground scene (gradient depth)
 * - Background sky (deep constant)
 * - Speech bubble (flat white region = perfect standing wave)
 * - Scan noise (random, should be rejected)
 *
 * Shows: temporal accumulation → layer separation → text slot ranking → parallax frames
 */

import {
  createPhyleTemporalPipeline,
  ingestFrame,
  type DepthFrame,
} from './phyle-temporal-depth';

import {
  separateParallaxLayers,
  rankTextSlots,
  computeParallaxMotion,
  generateAnimatedPanelFrames,
} from './phyle-comic-parallax';

const WIDTH = 128;
const HEIGHT = 128;
const PIX = WIDTH * HEIGHT;

// ─── Synthetic comic panel depth ────────────────────────────────────

function makeComicFrame(phase: number): DepthFrame {
  const values = new Float32Array(PIX);
  const confidence = new Float32Array(PIX);
  const deblurAdmission = new Float32Array(PIX);

  for (let y = 0; y < HEIGHT; y++) {
    for (let x = 0; x < WIDTH; x++) {
      const i = y * WIDTH + x;
      const nx = x / WIDTH;
      const ny = y / HEIGHT;

      // Character silhouette (foreground, center-bottom, low depth)
      const charDist = Math.sqrt((nx - 0.5) ** 2 + (ny - 0.7) ** 2);
      const isChar = charDist < 0.2;

      // Speech bubble (top-right, flat white, perfect text region)
      const bubbleDist = Math.sqrt((nx - 0.75) ** 2 + (ny - 0.25) ** 2);
      const isBubble = bubbleDist < 0.15;

      // Scan noise strip (bottom edge)
      const isNoise = ny > 0.92;

      if (isChar) {
        // Foreground character: constant depth + tiny phase jitter
        values[i] = 0.15 + phase * 0.001;
        confidence[i] = 0.95;
        deblurAdmission[i] = 0.9;
      } else if (isBubble) {
        // Speech bubble: perfectly constant (ideal standing wave)
        values[i] = 0.4;
        confidence[i] = 1.0;
        deblurAdmission[i] = 0.95;
      } else if (isNoise) {
        // Scan noise: random per-frame
        values[i] = Math.random();
        confidence[i] = 0.3;
        deblurAdmission[i] = Math.random() * 0.5;
      } else {
        // Background: depth gradient (far = high value)
        values[i] = 0.5 + ny * 0.4 + phase * 0.002;
        confidence[i] = 0.8;
        deblurAdmission[i] = 0.7 + (1 - ny) * 0.2;
      }
    }
  }

  return {
    values, confidence, deblurAdmission,
    width: WIDTH, height: HEIGHT, frameIndex: 0, timestamp: Date.now(),
  };
}

// Synthetic text region mask (speech bubble location)
function makeBubbleMask(): Uint8Array {
  const mask = new Uint8Array(PIX);
  for (let y = 0; y < HEIGHT; y++) {
    for (let x = 0; x < WIDTH; x++) {
      const nx = x / WIDTH;
      const ny = y / HEIGHT;
      const bubbleDist = Math.sqrt((nx - 0.75) ** 2 + (ny - 0.25) ** 2);
      if (bubbleDist < 0.12) {
        mask[y * WIDTH + x] = 255;
      }
    }
  }
  return mask;
}

// ─── Run the pipeline ───────────────────────────────────────────────

console.log('=== PHYLE COMIC PARALLAX PIPELINE ===\n');

const pipe = createPhyleTemporalPipeline(WIDTH, HEIGHT);

// Ingest 3 frames (one triton window)
console.log('Phase 1: Temporal accumulation (3 frames, 1 triton window)');
const t0 = performance.now();
for (let i = 0; i < 3; i++) {
  const result = ingestFrame(pipe, makeComicFrame(i));
  if (result) {
    console.log(`  Window complete: standing=${result.standingWaveCount} pink=${result.pinkResolved} white=${result.whiteDeferred}`);
  }
}
const t1 = performance.now();
console.log(`  Time: ${(t1 - t0).toFixed(1)}ms\n`);

// Separate parallax layers
console.log('Phase 2: Layer separation');
const parallax = separateParallaxLayers(pipe);
if (!parallax) {
  console.log('  ERROR: No parallax data');
  process.exit(1);
}

for (const layer of parallax.layers) {
  console.log(`  ${layer.id.padEnd(12)} pixels=${layer.pixelCount.toString().padStart(6)} ` +
    `meanDepth=${layer.meanDepth.toFixed(3)} parallax=${layer.parallaxScale} ` +
    `swCoverage=${(layer.standingWaveCoverage * 100).toFixed(0)}%`);
}
console.log(`  Noise rejected: ${parallax.noiseRejected} pixels`);
console.log('');

// Rank text slots
console.log('Phase 3: Text slot ranking (speech bubble detection)');
const textMask = makeBubbleMask();
const slots = rankTextSlots(parallax, textMask);
console.log(`  Text slots found: ${slots.length}`);
for (const slot of slots.slice(0, 3)) {
  console.log(`    [${slot.x0},${slot.y0} - ${slot.x1},${slot.y1}] ` +
    `layer=${slot.layer} confidence=${slot.standingWaveConfidence.toFixed(3)} ` +
    `area=${slot.area}`);
}
console.log('');

// Generate parallax motion
console.log('Phase 4: Parallax motion (gentle orbit)');
const motions = computeParallaxMotion(parallax, 0.3, 0.1);
for (const m of motions) {
  console.log(`  ${m.layerId.padEnd(12)} dx=${m.dx.toFixed(1)}px dy=${m.dy.toFixed(1)}px`);
}
console.log('');

// Generate animation frames
console.log('Phase 5: Animated panel frames (2s loop @ 30fps)');
const frames = generateAnimatedPanelFrames(parallax, 2000, 30);
console.log(`  Generated: ${frames.length} frames`);
console.log(`  First frame: ${JSON.stringify(frames[0]?.layers.map(l => ({ id: l.id, dx: l.offsetX.toFixed(1), dy: l.offsetY.toFixed(1) })))}`);
console.log(`  Mid frame:   ${JSON.stringify(frames[Math.floor(frames.length / 2)]?.layers.map(l => ({ id: l.id, dx: l.offsetX.toFixed(1), dy: l.offsetY.toFixed(1) })))}`);
console.log('');

// Summary
console.log('========================================================================');
console.log(' ARTISTIC VISION SUMMARY');
console.log('========================================================================');
console.log('');
console.log(` Comic panel: ${WIDTH}x${HEIGHT}`);
console.log(` Foreground (character): ${parallax.layers[0].pixelCount} pixels, parallax 1.0x`);
console.log(` Midground (scene): ${parallax.layers[1].pixelCount} pixels, parallax 0.5x`);
console.log(` Background (sky): ${parallax.layers[2].pixelCount} pixels, parallax 0.2x`);
console.log(` Speech bubble: ${slots.length > 0 ? `found at [${slots[0]!.x0},${slots[0]!.y0}], confidence ${slots[0]!.standingWaveConfidence.toFixed(3)}` : 'not found'}`);
console.log(` Noise rejected: ${parallax.noiseRejected} pixels (scan artifacts filtered)`);
console.log(` Animation: ${frames.length} frames for smooth parallax loop`);
console.log('');
console.log(' Static panel → living diorama. Characters float. Backgrounds recede.');
console.log(' Text anchors to standing-wave regions (temporally confirmed stable).');
console.log(' Scan noise filtered by the temporal triton (never rendered as phantom depth).');
